package sn.gestionimmobiliere.backend.receipt.application;
import java.io.*;import java.time.*;import java.time.format.DateTimeFormatter;import java.util.UUID;import org.apache.pdfbox.pdmodel.*;import org.apache.pdfbox.pdmodel.common.PDRectangle;import org.apache.pdfbox.pdmodel.font.Standard14Fonts;import org.apache.pdfbox.pdmodel.font.PDType1Font;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
import sn.gestionimmobiliere.backend.billing.application.BillingService;import sn.gestionimmobiliere.backend.billing.domain.RentCharge;import sn.gestionimmobiliere.backend.lease.application.LeaseService;import sn.gestionimmobiliere.backend.lease.domain.Lease;import sn.gestionimmobiliere.backend.owner.application.OwnerProperties;import sn.gestionimmobiliere.backend.receipt.api.ReceiptResponse;import sn.gestionimmobiliere.backend.receipt.domain.Receipt;import sn.gestionimmobiliere.backend.receipt.infrastructure.ReceiptRepository;import sn.gestionimmobiliere.backend.tenant.application.TenantService;import sn.gestionimmobiliere.backend.unit.application.UnitService;
@Service public class ReceiptService{private final ReceiptRepository repository;private final BillingService billing;private final LeaseService leases;private final TenantService tenants;private final UnitService units;private final OwnerProperties props;private final Clock clock;public ReceiptService(ReceiptRepository r,BillingService b,LeaseService l,TenantService t,UnitService u,OwnerProperties p,Clock c){repository=r;billing=b;leases=l;tenants=t;units=u;props=p;clock=c;}@Transactional public ReceiptResponse issue(UUID chargeId){RentCharge c=billing.entity(chargeId);if(c.getBalance()!=0)throw new IllegalArgumentException("La quittance exige une echeance integralement payee");Receipt receipt=repository.findByRentChargeIdAndOrganizationId(chargeId,props.organizationId()).orElseGet(()->repository.saveAndFlush(new Receipt(UUID.randomUUID(),props.organizationId(),chargeId,"QUIT-"+Year.now(clock)+"-"+UUID.randomUUID().toString().substring(0,8).toUpperCase(),clock.instant())));return map(receipt);}@Transactional(readOnly=true)public byte[] pdf(UUID id){Receipt r=repository.findByIdAndOrganizationId(id,props.organizationId()).orElseThrow(()->new IllegalArgumentException("Quittance introuvable"));RentCharge c=billing.entity(r.getRentChargeId());Lease l=leases.entity(c.getLeaseId());var tenant=tenants.one(l.getTenantId());var unit=units.findById(l.getUnitId());try(PDDocument doc=new PDDocument();ByteArrayOutputStream out=new ByteArrayOutputStream()){PDPage page=new PDPage(PDRectangle.A4);doc.addPage(page);try(PDPageContentStream cs=new PDPageContentStream(doc,page)){PDType1Font bold=new PDType1Font(Standard14Fonts.FontName.HELVETICA_BOLD);PDType1Font regular=new PDType1Font(Standard14Fonts.FontName.HELVETICA);text(cs,bold,18,60,780,"QUITTANCE DE LOYER");text(cs,regular,11,60,745,"Numero : "+r.getReceiptNumber());text(cs,regular,11,60,725,"Locataire : "+tenant.fullName());text(cs,regular,11,60,705,"Unite : "+unit.name());text(cs,regular,11,60,685,"Periode : "+c.getPeriodStart().format(DateTimeFormatter.ISO_DATE));text(cs,bold,13,60,650,"Montant acquitte : "+c.getAmountPaid()+" XOF");text(cs,regular,10,60,610,"Emise le "+r.getIssuedAt()+" - Agence Demo Senegal");}doc.save(out);return out.toByteArray();}catch(IOException e){throw new IllegalStateException("Generation PDF impossible",e);}}private void text(PDPageContentStream cs,PDType1Font f,float size,float x,float y,String value)throws IOException{cs.beginText();cs.setFont(f,size);cs.newLineAtOffset(x,y);cs.showText(value.replaceAll("[^\\x20-\\x7E]","?"));cs.endText();}private ReceiptResponse map(Receipt r){return new ReceiptResponse(r.getId(),r.getRentChargeId(),r.getReceiptNumber(),r.getIssuedAt());}}
